# Create comprehensive test suite

test_suite = '''
// ═════════════════════════════════════════════════════════════════════════════
// test_main.cpp - Test Suite Entry Point
// ═════════════════════════════════════════════════════════════════════════════

#define CATCH_CONFIG_MAIN
#include <catch2/catch.hpp>

// ═════════════════════════════════════════════════════════════════════════════
// test_json_parser.cpp - JSON Parser Tests
// ═════════════════════════════════════════════════════════════════════════════

#include "agent_kernel_main.hpp"
using namespace RawrXD;

TEST_CASE("JSON Parser - Basic Types", "[json]") {
    SECTION("Parse null") {
        auto result = JsonParser::Parse("null");
        REQUIRE(result.has_value());
        REQUIRE(std::holds_alternative<std::nullptr_t>(*result));
    }
    
    SECTION("Parse boolean") {
        auto resultTrue = JsonParser::Parse("true");
        REQUIRE(resultTrue.has_value());
        REQUIRE(std::get<bool>(*resultTrue) == true);
        
        auto resultFalse = JsonParser::Parse("false");
        REQUIRE(resultFalse.has_value());
        REQUIRE(std::get<bool>(*resultFalse) == false);
    }
    
    SECTION("Parse integer") {
        auto result = JsonParser::Parse("42");
        REQUIRE(result.has_value());
        REQUIRE(std::get<int64_t>(*result) == 42);
    }
    
    SECTION("Parse double") {
        auto result = JsonParser::Parse("3.14159");
        REQUIRE(result.has_value());
        REQUIRE(std::get<double>(*result) == Approx(3.14159));
    }
    
    SECTION("Parse string") {
        auto result = JsonParser::Parse("\\"hello world\\"");
        REQUIRE(result.has_value());
        REQUIRE(std::get<String>(*result) == L"hello world");
    }
}

TEST_CASE("JSON Parser - Arrays", "[json]") {
    SECTION("Parse empty array") {
        auto result = JsonParser::Parse("[]");
        REQUIRE(result.has_value());
        auto& arr = std::get<std::vector<JsonValue>>(*result);
        REQUIRE(arr.empty());
    }
    
    SECTION("Parse number array") {
        auto result = JsonParser::Parse("[1, 2, 3]");
        REQUIRE(result.has_value());
        auto& arr = std::get<std::vector<JsonValue>>(*result);
        REQUIRE(arr.size() == 3);
        REQUIRE(std::get<int64_t>(arr[0]) == 1);
        REQUIRE(std::get<int64_t>(arr[1]) == 2);
        REQUIRE(std::get<int64_t>(arr[2]) == 3);
    }
    
    SECTION("Parse mixed array") {
        auto result = JsonParser::Parse("[1, \\"two\\", true, null]");
        REQUIRE(result.has_value());
        auto& arr = std::get<std::vector<JsonValue>>(*result);
        REQUIRE(arr.size() == 4);
        REQUIRE(std::holds_alternative<int64_t>(arr[0]));
        REQUIRE(std::holds_alternative<String>(arr[1]));
        REQUIRE(std::holds_alternative<bool>(arr[2]));
        REQUIRE(std::holds_alternative<std::nullptr_t>(arr[3]));
    }
}

TEST_CASE("JSON Parser - Objects", "[json]") {
    SECTION("Parse empty object") {
        auto result = JsonParser::Parse("{}");
        REQUIRE(result.has_value());
        auto& obj = std::get<std::map<String, JsonValue>>(*result);
        REQUIRE(obj.empty());
    }
    
    SECTION("Parse simple object") {
        auto result = JsonParser::Parse("{\\"name\\": \\"John\\", \\"age\\": 30}");
        REQUIRE(result.has_value());
        auto& obj = std::get<std::map<String, JsonValue>>(*result);
        REQUIRE(obj.size() == 2);
        REQUIRE(std::get<String>(obj[L"name"]) == L"John");
        REQUIRE(std::get<int64_t>(obj[L"age"]) == 30);
    }
    
    SECTION("Parse nested object") {
        auto result = JsonParser::Parse(R"({
            "user": {
                "name": "Alice",
                "settings": {
                    "theme": "dark"
                }
            }
        })");
        REQUIRE(result.has_value());
        auto& obj = std::get<std::map<String, JsonValue>>(*result);
        auto& user = std::get<std::map<String, JsonValue>>(obj[L"user"]);
        auto& settings = std::get<std::map<String, JsonValue>>(user[L"settings"]);
        REQUIRE(std::get<String>(settings[L"theme"]) == L"dark");
    }
}

TEST_CASE("JSON Parser - Serialization", "[json]") {
    SECTION("Serialize object") {
        std::map<String, JsonValue> obj;
        obj[L"name"] = L"Test";
        obj[L"value"] = static_cast<int64_t>(42);
        obj[L"active"] = true;
        
        String json = StringUtils::FromUtf8(JsonParser::Serialize(obj));
        REQUIRE(json.find(L"\\"name\\": \\"Test\\"") != String::npos);
        REQUIRE(json.find(L"\\"value\\": 42") != String::npos);
        REQUIRE(json.find(L"\\"active\\": true") != String::npos);
    }
}

// ═════════════════════════════════════════════════════════════════════════════
// test_tool_execution.cpp - Tool Execution Tests
// ═════════════════════════════════════════════════════════════════════════════

#include "ToolExecutionEngine.hpp"

TEST_CASE("Tool Execution - Basic Commands", "[tools]") {
    ToolExecutionEngine engine;
    
    SECTION("Execute echo command") {
        auto result = engine.Execute(L"echo Hello World", {});
        REQUIRE(result.IsSuccess());
        REQUIRE(result.exitCode == 0);
        // Note: echo output includes newline
        REQUIRE(result.stdoutData.find(L"Hello World") != String::npos);
    }
    
    SECTION("Execute with working directory") {
        wchar_t tempPath[MAX_PATH];
        GetTempPathW(MAX_PATH, tempPath);
        
        auto result = engine.Execute(L"cd", tempPath);
        REQUIRE(result.IsSuccess());
        REQUIRE(result.stdoutData.find(tempPath) != String::npos);
    }
    
    SECTION("Execute failing command") {
        auto result = engine.Execute(L"cmd /c exit 1", {});
        REQUIRE_FALSE(result.IsSuccess());
        REQUIRE(result.exitCode == 1);
    }
    
    SECTION("Command timeout") {
        ProcessConfig config;
        config.command = L"timeout /t 10 /nobreak";
        config.timeout = std::chrono::milliseconds(100); // 100ms timeout
        
        auto process = engine.ExecuteAsync(config);
        REQUIRE(process != nullptr);
        
        auto start = std::chrono::steady_clock::now();
        process->WaitForFinished(std::chrono::milliseconds(5000));
        auto elapsed = std::chrono::steady_clock::now() - start;
        
        // Should have timed out quickly
        REQUIRE(elapsed < std::chrono::seconds(2));
    }
}

TEST_CASE("Tool Execution - File Operations", "[tools]") {
    ToolExecutionEngine engine;
    
    SECTION("Find executable") {
        auto cmdPath = ToolExecutionEngine::FindExecutable(L"cmd");
        REQUIRE_FALSE(cmdPath.empty());
        REQUIRE(cmdPath.find(L"cmd.exe") != String::npos);
    }
    
    SECTION("Check executable availability") {
        REQUIRE(ToolExecutionEngine::IsExecutableAvailable(L"cmd"));
        REQUIRE_FALSE(ToolExecutionEngine::IsExecutableAvailable(L"nonexistent_command_xyz"));
    }
}

TEST_CASE("Tool Execution - Batch Operations", "[tools]") {
    ToolExecutionEngine engine;
    
    SECTION("Execute batch with dependencies") {
        std::vector<ToolExecutionEngine::ToolTask> tasks;
        
        tasks.push_back({L"task1", L"echo Step 1", {}, false});
        tasks.push_back({L"task2", L"echo Step 2", {L"task1"}, false});
        tasks.push_back({L"task3", L"echo Step 3", {L"task2"}, false});
        
        auto result = engine.ExecuteBatch(tasks);
        REQUIRE(result.overallSuccess);
        REQUIRE(result.executionOrder.size() == 3);
        REQUIRE(result.executionOrder[0] == L"task1");
        REQUIRE(result.executionOrder[1] == L"task2");
        REQUIRE(result.executionOrder[2] == L"task3");
    }
}

// ═════════════════════════════════════════════════════════════════════════════
// test_agent_orchestrator.cpp - Agent Tests
// ═════════════════════════════════════════════════════════════════════════════

#include "AgentOrchestrator.hpp"

class MockLLMClient : public ILLMClient {
public:
    CompletionResponse Complete(const CompletionRequest& request) override {
        CompletionResponse response;
        response.success = true;
        response.content = L"[{\\"id\\": \\"1\\", \\"description\\": \\"Test task\\", \\"tool\\": \\"execute_command\\", \\"parameters\\": {\\"command\\": \\"echo test\\"}}]";
        return response;
    }
    
    void StreamComplete(const CompletionRequest& request, 
                       std::function<void(const String& chunk)> callback) override {
        callback(L"Test response");
    }
};

TEST_CASE("Agent Orchestrator - Initialization", "[agent]") {
    auto llmClient = std::make_shared<MockLLMClient>();
    auto toolEngine = std::make_shared<ToolExecutionEngine>();
    
    AgentOrchestrator::Config config;
    config.maxIterations = 10;
    config.enableSelfHealing = false;
    
    AgentOrchestrator orchestrator(llmClient, toolEngine, config);
    
    SECTION("Initial state") {
        REQUIRE(orchestrator.GetState() == AgentState::Idle);
    }
    
    SECTION("Execute simple task") {
        bool completed = false;
        orchestrator.SetCompletionCallback([&completed](bool success, const String& result) {
            completed = true;
        });
        
        REQUIRE(orchestrator.ExecuteTask(L"Test task"));
        REQUIRE(orchestrator.GetState() != AgentState::Idle);
    }
}

TEST_CASE("Agent Orchestrator - Error Handling", "[agent]") {
    auto llmClient = std::make_shared<MockLLMClient>();
    auto toolEngine = std::make_shared<ToolExecutionEngine>();
    
    AgentOrchestrator orchestrator(llmClient, toolEngine);
    
    SECTION("Cancel execution") {
        orchestrator.ExecuteTask(L"Long running task");
        orchestrator.Cancel();
        
        // Should eventually return to idle
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
        REQUIRE(orchestrator.GetState() == AgentState::Idle);
    }
}

TEST_CASE("Context Window Manager", "[agent]") {
    ContextWindowManager manager(1000);
    
    SECTION("Add messages") {
        manager.SetSystemPrompt(L"You are a helpful assistant");
        manager.AddMessage(L"user", L"Hello");
        manager.AddMessage(L"assistant", L"Hi there!");
        
        String prompt = manager.BuildPrompt();
        REQUIRE(prompt.find(L"system") != String::npos);
        REQUIRE(prompt.find(L"user") != String::npos);
        REQUIRE(prompt.find(L"assistant") != String::npos);
    }
    
    SECTION("Token estimation") {
        size_t tokens = manager.EstimateTokens(L"Hello world");
        REQUIRE(tokens > 0);
        REQUIRE(tokens < 100); // Should be reasonable
    }
}

TEST_CASE("Error Parser", "[agent]") {
    ErrorParser parser;
    
    SECTION("Parse MSVC errors") {
        String output = L"main.cpp(10,5): error C2065: 'x': undeclared identifier";
        auto errors = parser.ParseCompilerOutput(output, L"msvc");
        
        REQUIRE(errors.size() == 1);
        REQUIRE(errors[0].file == L"main.cpp");
        REQUIRE(errors[0].line == 10);
        REQUIRE(errors[0].column == 5);
        REQUIRE(errors[0].severity == L"error");
    }
    
    SECTION("Parse GCC errors") {
        String output = L"main.cpp:15:3: error: 'y' was not declared in this scope";
        auto errors = parser.ParseCompilerOutput(output, L"gcc");
        
        REQUIRE(errors.size() == 1);
        REQUIRE(errors[0].file == L"main.cpp");
        REQUIRE(errors[0].line == 15);
        REQUIRE(errors[0].severity == L"error");
    }
}

TEST_CASE("Diff Engine", "[agent]") {
    DiffEngine diffEngine;
    
    SECTION("Compute simple diff") {
        String oldText = L"line1\\nline2\\nline3";
        String newText = L"line1\\nmodified\\nline3";
        
        auto diff = diffEngine.ComputeDiff(oldText, newText, L"test.txt");
        REQUIRE(diff.hunks.size() > 0);
    }
    
    SECTION("Apply diff") {
        String oldText = L"hello world";
        String newText = L"hello modified world";
        
        auto diff = diffEngine.ComputeDiff(oldText, newText, L"test.txt");
        String result = diffEngine.ApplyDiff(oldText, diff);
        
        REQUIRE(result == newText);
    }
}

TEST_CASE("Multi-File Edit Manager", "[agent]") {
    MultiFileEditManager editManager;
    
    SECTION("Stage and apply edit") {
        editManager.StartSession(L"Test session");
        
        String filePath = L"test_file.txt";
        String newContent = L"new content";
        
        REQUIRE(editManager.StageEdit(filePath, newContent));
        
        auto pending = editManager.GetPendingEdits();
        REQUIRE(pending.size() == 1);
        
        editManager.CommitSession();
    }
}

// ═════════════════════════════════════════════════════════════════════════════
// Benchmark Tests
// ═════════════════════════════════════════════════════════════════════════════

TEST_CASE("Performance - JSON Parsing", "[!benchmark]") {
    std::string largeJson = R"({
        "users": [
    )";
    
    for (int i = 0; i < 1000; ++i) {
        largeJson += "{\\"id\\": " + std::to_string(i) + 
                    ", \\"name\\": \\"User" + std::to_string(i) + "\\"},";
    }
    largeJson += "{}]}";
    
    auto start = std::chrono::high_resolution_clock::now();
    auto result = JsonParser::Parse(largeJson);
    auto elapsed = std::chrono::high_resolution_clock::now() - start;
    
    REQUIRE(result.has_value());
    REQUIRE(elapsed < std::chrono::milliseconds(100)); // Should parse in <100ms
}

TEST_CASE("Performance - Tool Execution", "[!benchmark]") {
    ToolExecutionEngine engine;
    
    auto start = std::chrono::high_resolution_clock::now();
    
    for (int i = 0; i < 100; ++i) {
        engine.Execute(L"echo test", {});
    }
    
    auto elapsed = std::chrono::high_resolution_clock::now() - start;
    
    REQUIRE(elapsed < std::chrono::seconds(10)); // 100 executions in <10s
}
'''

print("Created test suite - Comprehensive unit tests")
print(f"Size: {len(test_suite)} characters")

# Create LSP (Language Server Protocol) Integration

lsp_integration = '''
// ═════════════════════════════════════════════════════════════════════════════
// LSPClient.hpp - Language Server Protocol Integration
// Replaces Qt-based LSP with pure C++20 implementation
// ═════════════════════════════════════════════════════════════════════════════

#pragma once
#include "agent_kernel_main.hpp"
#include "ToolExecutionEngine.hpp"
#include <atomic>
#include <deque>

namespace RawrXD {
namespace LSP {

// ═════════════════════════════════════════════════════════════════════════════
// LSP Types (based on Language Server Protocol specification)
// ═════════════════════════════════════════════════════════════════════════════

struct Position {
    int line{0};
    int character{0};
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"line"] = static_cast<int64_t>(line);
        obj[L"character"] = static_cast<int64_t>(character);
        return obj;
    }
};

struct Range {
    Position start;
    Position end;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"start"] = start.ToJson();
        obj[L"end"] = end.ToJson();
        return obj;
    }
};

struct Location {
    String uri;
    Range range;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"uri"] = uri;
        obj[L"range"] = range.ToJson();
        return obj;
    }
};

struct Diagnostic {
    Range range;
    int severity{1}; // 1=Error, 2=Warning, 3=Info, 4=Hint
    String code;
    String source;
    String message;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"range"] = range.ToJson();
        obj[L"severity"] = static_cast<int64_t>(severity);
        obj[L"code"] = code;
        obj[L"source"] = source;
        obj[L"message"] = message;
        return obj;
    }
};

struct TextEdit {
    Range range;
    String newText;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"range"] = range.ToJson();
        obj[L"newText"] = newText;
        return obj;
    }
};

struct CompletionItem {
    String label;
    int kind{1}; // 1=Text, 2=Method, 3=Function, etc.
    String detail;
    String documentation;
    String insertText;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"label"] = label;
        obj[L"kind"] = static_cast<int64_t>(kind);
        obj[L"detail"] = detail;
        obj[L"documentation"] = documentation;
        obj[L"insertText"] = insertText;
        return obj;
    }
};

struct SymbolInformation {
    String name;
    int kind{1};
    Location location;
    String containerName;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"name"] = name;
        obj[L"kind"] = static_cast<int64_t>(kind);
        obj[L"location"] = location.ToJson();
        obj[L"containerName"] = containerName;
        return obj;
    }
};

// ═════════════════════════════════════════════════════════════════════════════
// LSP Message Types
// ═════════════════════════════════════════════════════════════════════════════

enum class LSPMessageType {
    Request,
    Response,
    Notification
};

struct LSPMessage {
    LSPMessageType type;
    String jsonrpc{L"2.0"};
    Optional<String> id;
    String method;
    JsonValue params;
    Optional<JsonValue> result;
    Optional<JsonValue> error;
    
    JsonValue ToJson() const {
        std::map<String, JsonValue> obj;
        obj[L"jsonrpc"] = jsonrpc;
        if (id) obj[L"id"] = *id;
        if (!method.empty()) obj[L"method"] = method;
        if (std::holds_alternative<std::map<String, JsonValue>>(params)) {
            obj[L"params"] = params;
        }
        if (result) obj[L"result"] = *result;
        if (error) obj[L"error"] = *error;
        return obj;
    }
    
    static Optional<LSPMessage> FromJson(const JsonValue& json);
};

// ═════════════════════════════════════════════════════════════════════════════
// LSP Client - Manages connection to language server
// ═════════════════════════════════════════════════════════════════════════════
class LSPClient {
public:
    struct Config {
        String serverCommand;  // e.g., "clangd" or "pylsp"
        Vector<String> serverArgs;
        String workspaceRoot;
        std::chrono::milliseconds initTimeout{30000};
        std::chrono::milliseconds requestTimeout{10000};
    };
    
    explicit LSPClient(const Config& config);
    ~LSPClient();
    
    // Connection management
    bool Initialize();
    void Shutdown();
    bool IsConnected() const { return connected_; }
    
    // Text synchronization
    bool DidOpen(const String& uri, const String& languageId, const String& text);
    bool DidChange(const String& uri, const Vector<TextEdit>& changes);
    bool DidSave(const String& uri);
    bool DidClose(const String& uri);
    
    // Language features
    Vector<CompletionItem> Completion(const String& uri, const Position& position);
    Optional<Location> Definition(const String& uri, const Position& position);
    Vector<Location> References(const String& uri, const Position& position, bool includeDeclaration);
    Vector<TextEdit> Formatting(const String& uri);
    Vector<TextEdit> RangeFormatting(const String& uri, const Range& range);
    Vector<SymbolInformation> DocumentSymbol(const String& uri);
    Vector<SymbolInformation> WorkspaceSymbol(const String& query);
    Vector<TextEdit> Rename(const String& uri, const Position& position, const String& newName);
    Vector<Diagnostic> GetDiagnostics(const String& uri);
    
    // Hover and signature help
    Optional<String> Hover(const String& uri, const Position& position);
    // Optional<SignatureHelp> SignatureHelp(const String& uri, const Position& position);
    
    // Code actions
    // Vector<CodeAction> CodeAction(const String& uri, const Range& range, const Vector<Diagnostic>& diagnostics);
    
    // Callbacks
    using DiagnosticsCallback = std::function<void(const String& uri, const Vector<Diagnostic>& diagnostics)>;
    using LogCallback = std::function<void(const String& message)>;
    
    void SetDiagnosticsCallback(DiagnosticsCallback callback) { diagnosticsCallback_ = callback; }
    void SetLogCallback(LogCallback callback) { logCallback_ = callback; }

private:
    Config config_;
    std::atomic<bool> connected_{false};
    std::atomic<bool> initialized_{false};
    
    // Process management
    SharedPtr<AsyncProcess> serverProcess_;
    std::thread readerThread_;
    std::thread writerThread_;
    
    // Message handling
    std::atomic<int> nextId_{1};
    std::map<String, std::promise<JsonValue>> pendingRequests_;
    std::mutex pendingMutex_;
    
    std::deque<LSPMessage> outgoingQueue_;
    std::mutex queueMutex_;
    std::condition_variable queueCV_;
    
    // Document tracking
    std::map<String, String> openDocuments_;
    std::map<String, Vector<Diagnostic>> documentDiagnostics_;
    std::mutex documentsMutex_;
    
    DiagnosticsCallback diagnosticsCallback_;
    LogCallback logCallback_;
    
    // Internal methods
    bool StartServer();
    void StopServer();
    void ReaderLoop();
    void WriterLoop();
    void ProcessMessage(const String& message);
    
    String GenerateId();
    JsonValue SendRequest(const String& method, const JsonValue& params);
    void SendNotification(const String& method, const JsonValue& params);
    void SendResponse(const String& id, const JsonValue& result);
    void SendError(const String& id, int code, const String& message);
    
    void Log(const String& message);
};

// ═════════════════════════════════════════════════════════════════════════════
// LSP Server Manager - Manages multiple LSP servers for different languages
// ═════════════════════════════════════════════════════════════════════════════
class LSPServerManager {
public:
    void RegisterServer(const String& languageId, const LSPClient::Config& config);
    void UnregisterServer(const String& languageId);
    
    SharedPtr<LSPClient> GetClient(const String& languageId);
    SharedPtr<LSPClient> GetClientForFile(const String& filePath);
    
    Vector<String> GetSupportedLanguages() const;
    bool IsLanguageSupported(const String& languageId) const;
    
    // Auto-detect language from file extension
    static String DetectLanguage(const String& filePath);

private:
    std::map<String, SharedPtr<LSPClient>> servers_;
    mutable std::mutex mutex_;
    
    static std::map<String, String> extensionToLanguage_;
};

// ═════════════════════════════════════════════════════════════════════════════
// Implementation
// ═════════════════════════════════════════════════════════════════════════════

LSPClient::LSPClient(const Config& config) : config_(config) {}

LSPClient::~LSPClient() {
    Shutdown();
}

bool LSPClient::Initialize() {
    if (connected_) return true;
    
    if (!StartServer()) {
        Log(L"Failed to start LSP server");
        return false;
    }
    
    // Send initialize request
    std::map<String, JsonValue> params;
    params[L"processId"] = static_cast<int64_t>(GetCurrentProcessId());
    
    std::map<String, JsonValue> rootUri;
    rootUri[L"uri"] = String(L"file://") + config_.workspaceRoot;
    params[L"rootUri"] = config_.workspaceRoot;
    
    std::map<String, JsonValue> capabilities;
    // Set client capabilities
    params[L"capabilities"] = capabilities;
    
    auto result = SendRequest(L"initialize", params);
    
    if (std::holds_alternative<std::map<String, JsonValue>>(result)) {
        connected_ = true;
        initialized_ = true;
        
        // Send initialized notification
        SendNotification(L"initialized", std::map<String, JsonValue>{});
        
        Log(L"LSP client initialized successfully");
        return true;
    }
    
    Log(L"LSP initialization failed");
    StopServer();
    return false;
}

void LSPClient::Shutdown() {
    if (!connected_) return;
    
    // Send shutdown request
    SendRequest(L"shutdown", std::map<String, JsonValue>{});
    SendNotification(L"exit", std::map<String, JsonValue>{});
    
    StopServer();
    connected_ = false;
    initialized_ = false;
}

bool LSPClient::StartServer() {
    ProcessConfig procConfig;
    procConfig.command = config_.serverCommand;
    for (const auto& arg : config_.serverArgs) {
        procConfig.command += L" " + arg;
    }
    
    ToolExecutionEngine engine;
    serverProcess_ = engine.ExecuteAsync(procConfig);
    
    if (!serverProcess_) {
        return false;
    }
    
    // Start reader/writer threads
    readerThread_ = std::thread(&LSPClient::ReaderLoop, this);
    writerThread_ = std::thread(&LSPClient::WriterLoop, this);
    
    return true;
}

void LSPClient::StopServer() {
    if (serverProcess_) {
        serverProcess_->Terminate();
        serverProcess_.reset();
    }
    
    if (readerThread_.joinable()) {
        readerThread_.join();
    }
    if (writerThread_.joinable()) {
