JsonValue LSPClient::SendRequest(const String& method, const JsonValue& params) {
    String id = GenerateId();
    
    LSPMessage msg;
    msg.type = LSPMessageType::Request;
    msg.id = id;
    msg.method = method;
    msg.params = params;
    
    // Create promise for response
    std::promise<JsonValue> promise;
    std::future<JsonValue> future = promise.get_future();
    
    {
        std::lock_guard<std::mutex> lock(pendingMutex_);
        pendingRequests_[id] = std::move(promise);
    }
    
    // Queue message
    {
        std::lock_guard<std::mutex> lock(queueMutex_);
        outgoingQueue_.push_back(msg);
    }
    queueCV_.notify_one();
    
    // Wait for response
    auto status = future.wait_for(config_.requestTimeout);
    if (status == std::future_status::timeout) {
        std::lock_guard<std::mutex> lock(pendingMutex_);
        pendingRequests_.erase(id);
        return nullptr;
    }
    
    return future.get();
}

void LSPClient::SendNotification(const String& method, const JsonValue& params) {
    LSPMessage msg;
    msg.type = LSPMessageType::Notification;
    msg.method = method;
    msg.params = params;
    
    std::lock_guard<std::mutex> lock(queueMutex_);
    outgoingQueue_.push_back(msg);
    queueCV_.notify_one();
}

