    std::map<String, JsonValue> textDoc;
    textDoc[L"uri"] = uri;
    textDoc[L"languageId"] = languageId;
    textDoc[L"version"] = static_cast<int64_t>(1);
    textDoc[L"text"] = text;
    
    params[L"textDocument"] = textDoc;
    
    {
        std::lock_guard<std::mutex> lock(documentsMutex_);
        openDocuments_[uri] = text;
    }
    
    SendNotification(L"textDocument/didOpen", params);
    return true;
}

bool LSPClient::DidChange(const String& uri, const Vector<TextEdit>& changes) {
    std::map<String, JsonValue> params;
    params[L"uri"] = uri;
    
    std::vector<JsonValue> contentChanges;
    for (const auto& edit : changes) {
        contentChanges.push_back(edit.ToJson());
    }
    params[L"contentChanges"] = contentChanges;
    
    SendNotification(L"textDocument/didChange", params);
    return true;
}

Vector<CompletionItem> LSPClient::Completion(const String& uri, const Position& position) {
    std::map<String, JsonValue> params;
    
    std::map<String, JsonValue> textDoc;
    textDoc[L"uri"] = uri;
    params[L"textDocument"] = textDoc;
    params[L"position"] = position.ToJson();
    
    auto result = SendRequest(L"textDocument/completion", params);
    
    Vector<CompletionItem> items;
    
    if (std::holds_alternative<std::map<String, JsonValue>>(result)) {
        const auto& obj = std::get<std::map<String, JsonValue>>(result);
        auto itemsIt = obj.find(L"items");
        if (itemsIt != obj.end() && std::holds_alternative<std::vector<JsonValue>>(itemsIt->second)) {
            const auto& arr = std::get<std::vector<JsonValue>>(itemsIt->second);
            for (const auto& itemJson : arr) {
                if (std::holds_alternative<std::map<String, JsonValue>>(itemJson)) {
                    const auto& itemObj = std::get<std::map<String, JsonValue>>(itemJson);
                    CompletionItem item;
                    auto labelIt = itemObj.find(L"label");
                    if (labelIt != itemObj.end() && std::holds_alternative<String>(labelIt->second)) {
                        item.label = std::get<String>(labelIt->second);
                    }
                    items.push_back(item);
                }
            }
        }
    }
    
    return items;
}

Optional<Location> LSPClient::Definition(const String& uri, const Position& position) {
    std::map<String, JsonValue> params;
    
    std::map<String, JsonValue> textDoc;
    textDoc[L"uri"] = uri;
    params[L"textDocument"] = textDoc;
    params[L"position"] = position.ToJson();
    
    auto result = SendRequest(L"textDocument/definition", params);
    
    if (std::holds_alternative<std::map<String, JsonValue>>(result)) {
        const auto& obj = std::get<std::map<String, JsonValue>>(result);
        Location loc;
        auto uriIt = obj.find(L"uri");
        if (uriIt != obj.end() && std::holds_alternative<String>(uriIt->second)) {
            loc.uri = std::get<String>(uriIt->second);
        }
        return loc;
    }
    
    return std::nullopt;
}

