String LSPServerManager::DetectLanguage(const String& filePath) {
    size_t dotPos = filePath.rfind(L'.');
    if (dotPos != String::npos) {
        String ext = filePath.substr(dotPos);
        auto it = extensionToLanguage_.find(ext);
        if (it != extensionToLanguage_.end()) {
            return it->second;
        }
    }
    return L"plaintext";
}

