MCPResponse MCPServer::HandleInitialize(const MCPRequest& req) {
    // Check protocol version
    if (std::holds_alternative<std::map<String, JsonValue>>(req.params)) {
        const auto& params = std::get<std::map<String, JsonValue>>(req.params);
        auto versionIt = params.find(L"protocolVersion");
        if (versionIt != params.end() && std::holds_alternative<String>(versionIt->second)) {
            String version = std::get<String>(versionIt->second);
            if (version != L"2024-11-05") { // Current MCP version
                return CreateErrorResponse(req.id, MCPErrorCode::UnknownProtocolVersion,
                                         L"Unsupported protocol version");
            }
        }
    }
    
    initialized_ = true;
    
    // Build capabilities
    std::map<String, JsonValue> capabilities;
    capabilities[L"tools"] = std::map<String, JsonValue>{{L"listChanged", true}};
    capabilities[L"resources"] = std::map<String, JsonValue>{{L"listChanged", true}};
    capabilities[L"prompts"] = std::map<String, JsonValue>{{L"listChanged", true}};
    
    std::map<String, JsonValue> result;
    result[L"protocolVersion"] = L"2024-11-05";
    result[L"capabilities"] = capabilities;
    result[L"serverInfo"] = std::map<String, JsonValue>{
        {L"name", config_.serverName},
        {L"version", config_.serverVersion}
    };
    
    return CreateSuccessResponse(req.id, result);
}

MCPResponse MCPServer::HandleInitialized(const MCPRequest& req) {
    // Client acknowledges initialization
    return CreateSuccessResponse(req.id, std::map<String, JsonValue>{});
}

MCPResponse MCPServer::HandleShutdown(const MCPRequest& req) {
    initialized_ = false;
    return CreateSuccessResponse(req.id, nullptr);
}

MCPResponse MCPServer::HandleExit(const MCPRequest& req) {
