    return CreateSuccessResponse(req.id, nullptr);
}

MCPResponse MCPServer::HandleToolsList(const MCPRequest& req) {
    std::lock_guard<std::mutex> lock(capabilitiesMutex_);
    
    std::vector<JsonValue> toolsJson;
    for (const auto& tool : tools_) {
        std::map<String, JsonValue> toolObj;
        toolObj[L"name"] = tool.name;
        toolObj[L"description"] = tool.description;
        toolObj[L"inputSchema"] = tool.inputSchema;
        toolsJson.push_back(toolObj);
    }
    
    // Add built-in tools from agent
    if (agent_) {
        auto agentTools = agent_->toolRegistry_->GetAllTools();
        for (const auto& tool : agentTools) {
            std::map<String, JsonValue> toolObj;
            toolObj[L"name"] = tool.name;
            toolObj[L"description"] = tool.description;
            toolsJson.push_back(toolObj);
        }
    }
    
    std::map<String, JsonValue> result;
    result[L"tools"] = toolsJson;
    
    return CreateSuccessResponse(req.id, result);
}

MCPResponse MCPServer::HandleToolsCall(const MCPRequest& req) {
    if (!agent_) {
        return CreateErrorResponse(req.id, MCPErrorCode::InternalError,
                                 L"Agent not available");
    }
    
    if (!std::holds_alternative<std::map<String, JsonValue>>(req.params)) {
        return CreateErrorResponse(req.id, MCPErrorCode::InvalidParams,
                                 L"Invalid parameters");
    }
    
    const auto& params = std::get<std::map<String, JsonValue>>(req.params);
    
    auto nameIt = params.find(L"name");
    if (nameIt == params.end() || !std::holds_alternative<String>(nameIt->second)) {
        return CreateErrorResponse(req.id, MCPErrorCode::InvalidParams,
                                 L"Missing tool name");
    }
    
    String toolName = std::get<String>(nameIt->second);
    
    JsonValue arguments;
    auto argsIt = params.find(L"arguments");
    if (argsIt != params.end()) {
        arguments = argsIt->second;
    }
    
    // Execute tool via agent
    JsonValue result = agent_->toolRegistry_->ExecuteTool(toolName, arguments);
    
    std::map<String, JsonValue> response;
    response[L"content"] = std::vector<JsonValue>{
        std::map<String, JsonValue>{{L"type", L"text"}, {L"text", JsonParser::Serialize(result)}}
    };
    
    return CreateSuccessResponse(req.id, response);
}

MCPResponse MCPServer::HandleResourcesList(const MCPRequest& req) {
    std::lock_guard<std::mutex> lock(capabilitiesMutex_);
    
    std::vector<JsonValue> resourcesJson;
    for (const auto& res : resources_) {
        std::map<String, JsonValue> resObj;
        resObj[L"uri"] = res.uri;
        resObj[L"name"] = res.name;
        resObj[L"description"] = res.description;
        resObj[L"mimeType"] = res.mimeType;
        resourcesJson.push_back(resObj);
    }
    
    std::map<String, JsonValue> result;
    result[L"resources"] = resourcesJson;
    
    return CreateSuccessResponse(req.id, result);
}

MCPResponse MCPServer::HandleResourcesRead(const MCPRequest& req) {
    if (!std::holds_alternative<std::map<String, JsonValue>>(req.params)) {
        return CreateErrorResponse(req.id, MCPErrorCode::InvalidParams,
                                 L"Invalid parameters");
    }
    
    const auto& params = std::get<std::map<String, JsonValue>>(req.params);
    auto uriIt = params.find(L"uri");
    if (uriIt == params.end() || !std::holds_alternative<String>(uriIt->second)) {
        return CreateErrorResponse(req.id, MCPErrorCode::InvalidParams,
                                 L"Missing resource URI");
    }
    
    String uri = std::get<String>(uriIt->second);
    
    // Read file content
    String content;
    if (uri.find(L"file://") == 0) {
        String path = uri.substr(7);
        HANDLE hFile = CreateFileW(path.c_str(), GENERIC_READ, FILE_SHARE_READ,
                                  nullptr, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, nullptr);
        if (hFile != INVALID_HANDLE_VALUE) {
            LARGE_INTEGER size;
            GetFileSizeEx(hFile, &size);
            
            std::vector<char> buffer(static_cast<size_t>(size.QuadPart));
            DWORD bytesRead;
            ReadFile(hFile, buffer.data(), static_cast<DWORD>(size.QuadPart), &bytesRead, nullptr);
            CloseHandle(hFile);
            
            content = StringUtils::FromUtf8(std::string(buffer.data(), bytesRead));
        }
    }
    
    std::map<String, JsonValue> result;
    result[L"contents"] = std::vector<JsonValue>{
        std::map<String, JsonValue>{
            {L"uri", uri},
            {L"mimeType", L"text/plain"},
            {L"text", content}
        }
    };
    
    return CreateSuccessResponse(req.id, result);
}

MCPResponse MCPServer::HandlePromptsList(const MCPRequest& req) {
    std::lock_guard<std::mutex> lock(capabilitiesMutex_);
    
    std::vector<JsonValue> promptsJson;
    for (const auto& prompt : prompts_) {
        std::map<String, JsonValue> promptObj;
        promptObj[L"name"] = prompt.name;
        promptObj[L"description"] = prompt.description;
        
        std::vector<JsonValue> argsJson;
        for (const auto& [name, desc] : prompt.arguments) {
            argsJson.push_back(std::map<String, JsonValue>{
                {L"name", name},
                {L"description", desc}
            });
        }
        promptObj[L"arguments"] = argsJson;
        
        promptsJson.push_back(promptObj);
    }
    
    std::map<String, JsonValue> result;
    result[L"prompts"] = promptsJson;
    
    return CreateSuccessResponse(req.id, result);
}

