    return CreateSuccessResponse(req.id, std::map<String, JsonValue>{{L"completion", L""}});
}

MCPResponse MCPServer::CreateErrorResponse(const String& id, MCPErrorCode code, 
                                          const String& message) {
    MCPResponse resp;
    resp.id = id;
    resp.error = MCPError{static_cast<int>(code), message, std::nullopt};
    return resp;
}

MCPResponse MCPServer::CreateSuccessResponse(const String& id, const JsonValue& result) {
    MCPResponse resp;
    resp.id = id;
    resp.result = result;
    return resp;
}

// ═════════════════════════════════════════════════════════════════════════════
// RawrXD as MCP Tool Provider
// ═════════════════════════════════════════════════════════════════════════════

class RawrXDMCPAdapter {
public:
    static void RegisterRawrXDTools(MCPServer& server, SharedPtr<AgentOrchestrator> agent) {
        // Register all RawrXD tools as MCP tools
        if (!agent) return;
        
        auto tools = agent->toolRegistry_->GetAllTools();
        for (const auto& tool : tools) {
            MCPTool mcpTool;
            mcpTool.name = tool.name;
            mcpTool.description = tool.description;
            
            // Build input schema
            std::map<String, JsonValue> schema;
            schema[L"type"] = L"object";
            schema[L"properties"] = std::map<String, JsonValue>{};
            schema[L"required"] = std::vector<JsonValue>{};
            
            mcpTool.inputSchema = schema;
            
            server.RegisterTool(mcpTool);
        }
        
        // Register resources for workspace
        MCPResource workspaceRes;
        workspaceRes.uri = L"file://" + agent->context_.workingDirectory;
        workspaceRes.name = L"Workspace";
        workspaceRes.description = L"RawrXD workspace root";
        workspaceRes.mimeType = L"text/plain";
        server.RegisterResource(workspaceRes);
        
        // Register prompts
        MCPPrompt codePrompt;
        codePrompt.name = L"generate_code";
        codePrompt.description = L"Generate code with RawrXD Agent";
        codePrompt.arguments = {{L"description", L"What to generate"}};
        server.RegisterPrompt(codePrompt);
    }
};

} // namespace MCP
} // namespace RawrXD
