        config.autoApprove = (_wcsicmp(buffer, L"1") == 0 || _wcsicmp(buffer, L"true") == 0);
    }
    if (GetEnvironmentVariableW(L"RAWRXD_MAX_ITERATIONS", buffer, MAX_PATH) > 0) {
        config.maxIterations = _wtoi(buffer);
    }
    
    // LSP
    if (GetEnvironmentVariableW(L"RAWRXD_ENABLE_LSP", buffer, MAX_PATH) > 0) {
        config.enableLSP = (_wcsicmp(buffer, L"0") != 0 && _wcsicmp(buffer, L"false") != 0);
    }
    
    // Vector DB
    if (GetEnvironmentVariableW(L"RAWRXD_ENABLE_VDB", buffer, MAX_PATH) > 0) {
        config.enableVectorDB = (_wcsicmp(buffer, L"0") != 0 && _wcsicmp(buffer, L"false") != 0);
    }
    
    // MCP
    if (GetEnvironmentVariableW(L"RAWRXD_ENABLE_MCP", buffer, MAX_PATH) > 0) {
        config.enableMCP = (_wcsicmp(buffer, L"0") != 0 && _wcsicmp(buffer, L"false") != 0);
