        config.enableUI = (_wcsicmp(buffer, L"0") != 0 && _wcsicmp(buffer, L"false") != 0);
    }
    
    GetCurrentDirectoryW(MAX_PATH, buffer);
    config.workingDirectory = buffer;
    
