    std::wcout << L"[Init] 3/6 Initializing Agent Orchestrator...\\n";
    AgentOrchestrator::Config agentConfig;
    agentConfig.maxIterations = config.maxIterations;
    agentConfig.autoApproveFilesystem = config.autoApprove;
    agentConfig.defaultModel = config.defaultModel;
    
