        g_app.lspManager = std::make_shared<LSP::LSPServerManager>();
        
        // Register C++ server (clangd)
        LSP::LSPClient::Config clangdConfig;
        clangdConfig.serverCommand = config.clangdPath;
        clangdConfig.workspaceRoot = config.workingDirectory;
        g_app.lspManager->RegisterServer(L"cpp", clangdConfig);
        
        // Register Python server (pylsp)
        LSP::LSPClient::Config pylspConfig;
        pylspConfig.serverCommand = config.pylspPath;
        pylspConfig.workspaceRoot = config.workingDirectory;
        g_app.lspManager->RegisterServer(L"python", pylspConfig);
        
        std::wcout << L"[Init]     ✓ LSP Manager ready\\n\\n";
    } else {
        std::wcout << L"[Init] 4/6 LSP disabled\\n\\n";
