        if (arg == L"--no-ui" || arg == L"-n") {
            config.enableUI = false;
        } else if (arg == L"--no-lsp" || arg == L"-l") {
            config.enableLSP = false;
        } else if (arg == L"--no-vdb" || arg == L"-v") {
            config.enableVectorDB = false;
        } else if (arg == L"--no-mcp" || arg == L"-m") {
            config.enableMCP = false;
        } else if (arg == L"--auto-approve" || arg == L"-a") {
            config.autoApprove = true;
        } else if (arg == L"--model" && i + 1 < argc) {
            config.defaultModel = argv[++i];
        } else if (arg == L"--help" || arg == L"-h") {
            std::wcout << L"Usage: RawrXD_Agent [options]\\n";
            std::wcout << L"Options:\\n";
            std::wcout << L"  -n, --no-ui          Disable UI (console only)\\n";
