            std::wcout << L"  -m, --no-mcp         Disable MCP server\\n";
            std::wcout << L"  -a, --auto-approve   Auto-approve filesystem changes\\n";
            std::wcout << L"  --model <name>       Set default LLM model\\n";
            std::wcout << L"  -h, --help           Show this help\\n";
            return 0;
        }
    }
    
    // Initialize
    if (!InitializeComponents(config)) {
        return 1;
    }
    
    // Setup signal handlers
    signal(SIGINT, SignalHandler);
    signal(SIGTERM, SignalHandler);
    
    // Print ready message
    std::wcout << L"══════════════════════════════════════════════════════════════════\\n";
    std::wcout << L"RawrXD Agent is ready!\\n";
    std::wcout << L"══════════════════════════════════════════════════════════════════\\n";
    std::wcout << L"\\n";
    std::wcout << L"Available commands:\\n";
    std::wcout << L"  Type a task description to execute\\n";
    std::wcout << L"  'search <query>' - Semantic code search\\n";
    std::wcout << L"  'index' - Re-index codebase\\n";
    std::wcout << L"  'status' - Show agent status\\n";
    std::wcout << L"  'quit' or 'exit' - Shutdown\\n";
    std::wcout << L"\\n";
    
    // Main loop
    while (g_app.running) {
        if (!config.enableUI || !g_app.chatWindow || !g_app.chatWindow->IsVisible()) {
            std::wcout << L"> ";
            
            String input;
            std::getline(std::wcin, input);
            
            if (input == L"quit" || input == L"exit") {
                break;
            }
            
            if (input == L"status") {
                std::wcout << L"Agent State: " << static_cast<int>(g_app.agent->GetState()) << L"\\n";
                std::wcout << L"Documents Indexed: " << (g_app.indexer ? g_app.indexer->GetDocumentCount() : 0) << L"\\n";
                std::wcout << L"MCP Server: " << (g_app.mcpServer && g_app.mcpServer->IsRunning() ? L"Running" : L"Stopped") << L"\\n";
                continue;
            }
            
            if (input == L"index") {
                if (g_app.indexer) {
                    std::wcout << L"Re-indexing workspace...\\n";
                    // Re-index
                } else {
                    std::wcout << L"Vector DB disabled\\n";
                }
                continue;
            }
            
            if (input.starts_with(L"search ")) {
                String query = input.substr(7);
                if (g_app.indexer) {
                    auto results = g_app.indexer->Search(query, 5);
                    std::wcout << L"Search results:\\n";
                    for (const auto& res : results) {
                        std::wcout << L"  " << res.score << L" - " << res.document.filePath 
                                  << L":" << res.document.startLine << L"\\n";
                    }
                } else {
                    std::wcout << L"Vector DB disabled\\n";
                }
                continue;
            }
            
            if (input.empty()) {
                continue;
            }
            
            // Execute task
            if (!g_app.agent->ExecuteTask(input)) {
                std::wcerr << L"[Error] Failed to start task\\n";
            }
            
            // Wait for completion
            while (g_app.agent->GetState() != AgentState::Idle &&
                   g_app.agent->GetState() != AgentState::Completed &&
                   g_app.agent->GetState() != AgentState::Failed &&
                   g_app.running) {
                std::this_thread::sleep_for(std::chrono::milliseconds(100));
            }
        } else {
            // UI mode - pump messages
            MSG msg;
            while (PeekMessage(&msg, nullptr, 0, 0, PM_REMOVE)) {
                TranslateMessage(&msg);
                DispatchMessage(&msg);
            }
            
            if (!g_app.chatWindow->IsVisible()) {
                break;
            }
            
            std::this_thread::sleep_for(std::chrono::milliseconds(16));
        }
    }
    
    // Cleanup
    std::wcout << L"\\n[RawrXD] Shutting down...\\n";
    
    g_app.chatWindow.reset();
    g_app.mcpServer.reset();
    g_app.indexer.reset();
    g_app.lspManager.reset();
    g_app.agent.reset();
    
    std::wcout << L"[RawrXD] Goodbye!\\n";
    
    return 0;
}

